import React from 'react';
import {
    Container, Table, Modal, Row, Col,
    Button,
    // Pagination, Button, Modal, Row, Col, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';

import PropTypes from 'prop-types';
import ReactHTMLTableToExcel from 'react-html-table-to-excel';
import logo from "../logo.png";
// import "./report-styles.css";    // If we use HTML to Excel, CSS style won't work. Must use inline style.

import { DataContext } from '../data-context.js';
import moment from 'moment'; // https://momentjs.com/
import { css } from '@emotion/core';
import GridLoader from 'react-spinners/GridLoader'; // https://www.react-spinners.com/

const util = require('../util.js');
const override = css`
    display: block;
    margin: 0 auto;
    border-color: red;
`;

// const styleAllBorders = css`
//     border: thin solid black;
//     text-align: center
// `;

// const _cssCirlcle = css`
//     background: #f00;
//     width: 200px;
//     height: 200px;
//     border-radius: 50%;
//     `;

const cssCirlcle = {
    // background: '#f00',
    border: 'thin solid #000',
    width: '20px',
    height: '20px',
    borderRadius: '50%'
};

const styleAllBorders = {
    border: 'thin solid #000',
    textAlign: 'center'
}

const styleNoBorders = {
    border: 'none',
    textAlign: 'center'
}
export default class DailyReport extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        startDate: PropTypes.string,
        endDate: PropTypes.string,
        onClose: PropTypes.func,
    };

    data = {};
    vendors = [];
    vendorMap = {};

    users = [];
    userMap = {};
    limit = 0;

    constructor(...args) {
        super(...args);

        this.state = {
            startDate: this.props.startDate,
            endDate: this.props.endDate,
            loading: false,
        }

        console.log(this.state)


        this.handleKeyDown = this.handleKeyDown.bind(this);
    }

    handleKeyDown = function (event) {
        switch (event.keyCode) {
            case 27:
                this.props.onClose()
                break;
            default:
                break;
        }

    }


    // UNSAFE_componentWillReceiveProps() {
    UNSAFE_componentWillMount() {
        // static getDerivedStateFromProps(props, state) {
        console.log('UNSAFE_componentWillReceiveProps fetchJobsByRange', this.props.startDate, this.props.endDate)
        // this.fetchjobs();

        document.addEventListener("keydown", this.handleKeyDown);
        this.setState(
            { loading: true },
            () => util.fetchJobsByRange(this.state.startDate, this.state.endDate)
                .then(res => this.setState({
                    jobs: res.data,
                    loading: false
                }))
        )
    }

    // fetchjobs() {
    //     util.fetchjobs(this.state.part._id,
    //         (res) => {
    //             console.log('fetchTransaction', res);
    //             this.setState({
    //                 jobs: res.data
    //             });
    //         },
    //         (err) => {
    //             console.error(err);
    //         }, this.limit);
    // }




    render() {
        // let part = this.props.part;
        // let users = this.state.users;
        // console.log('part', part)

        /* show={this.state.showDatePickerForm} */
        // console.log('jobs', this.state.jobs);
        if (this.state.loading) {
            return (
                <Container className="d-flex align-items-center" fluid style={{ backgroundColor: '#ffffff', minHeight: '100vh' }}>
                    <GridLoader
                        css={override}
                        sizeUnit={"px"}
                        size={80}
                        color={'#4A90E2'}
                        loading={this.props.loading}
                    />

                </Container>
            )
        }
        if (!this.state.jobs || this.state.jobs.length === 0) {
            return (
                <Modal
                    show={true}
                    onHide={this.props.onClose}
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    keyboard>
                    <Modal.Header closeButton>
                        <Modal.Title>Daily Report</Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <h2>No Data on {this.props.startDate}</h2>
                    </Modal.Body>
                    <Modal.Footer>
                        <Button onClick={this.props.onClose}>Close</Button>
                    </Modal.Footer>
                </Modal>
            )
        }

        let totalRepairJobs = this.state.jobs.length
        let totalSetupJobs = 0
        let totalBreakdownJobs = 0
        let totalOtherJobs = 0
        let totalRepairTime = 0
        let totalSetupTime = 0
        let totalBreakdownTime = 0
        let totalOtherTime = 0
        let successCount = 0
        let totalRunMachineTime = 0 // ???
        let totalRepairMan = 0
        let averageRepairTime = 0
        let totalWaitForRepairTime = 0 // ???
        let repairManMap = new Set()
        let unfinishedJob = 0
        let troubleMachines = [];

        let jobs = this.state.jobs.map((v, i) => {


            let rqTime = moment(v.request_time)
            let rpTime = moment(v.repair_time)
            let fTime = moment(v.finish_time)

            // console.log(v.finish_time,fTime)
            if (v.finish_time === null || v.finish_time === '') {
                unfinishedJob++;
                console.log('troubler:',v)
                troubleMachines.push(
                    <tr style={{height: '44px'}} key={unfinishedJob} >
                        <td style={styleAllBorders}>{unfinishedJob}</td>
                        {/* <td style={styleAllBorders}>{v.code}</td> */}
                        <td style={styleAllBorders}>{v.machine_code}</td>
                        {/* <td style={styleAllBorders}>{v.machine.code}</td> */}
                        <td colSpan={2} style={styleAllBorders}>{v.machine_name}</td>
                        <td style={styleAllBorders}>{v.line_name}</td>
                        <td colSpan={3} className="l">{v.request_cause}</td>
                        <td style={styleAllBorders}>{v.request_user_name}</td>
                        <td style={styleAllBorders}>-</td>
                    </tr>
                )
            }

            let ms, d;

            ms = rpTime.diff(rqTime)
            if (!isNaN(ms))
                totalWaitForRepairTime += ms
            // console.log('wait time',(typeof(ms)), ms, totalWaitForRepairTime)

            ms = fTime.diff(rpTime);

            // d = moment.duration(ms);
            // totalRepairTime += d;

            let respondTime = util.getDurationTimeText(rpTime.diff(rqTime))
            let repairTime = util.getDurationTimeText(ms)
            // let repairTime = Math.floor(d.asHours()) + moment.utc(ms).format(":mm:ss");
            // totalRepairTime += d.as('ms');

            ms = fTime.diff(rqTime);
            totalRunMachineTime += ms;
            let downTime = util.getDurationTimeText(ms)
            // d = moment.duration(ms);
            // let downTime = Math.floor(d.asHours()) + moment.utc(ms).format(":mm:ss");

            // Other calculations
            if (v.finish_work_type === 'SETUP') {
                totalSetupJobs++;
                // totalSetupTime += d.as('milliseconds'); // 50291000
                totalSetupTime += ms;

            } else if (v.finish_work_type === 'BREAK DOWN') {
                totalBreakdownJobs++;
                // totalBreakdownTime += d.as('milliseconds');
                totalBreakdownTime += ms
            } else if (v.finish_work_type === 'OTHER') {
                totalOtherJobs++;
                // totalOtherTime += d.as('milliseconds');
                totalOtherTime += ms
            }

            if (v.repair_user_code !== '')
                // repairManMap.add(v.repair_user_code)
                repairManMap.add(v.repair_user_name)


            return (
                <tr style={{height: '40px'}} key={i + 1}>
                    <td style={styleAllBorders}>{i + 1}</td>
                    <td style={styleAllBorders}>{v.code}</td>
                    <td style={styleAllBorders}>{v.machine_code}</td>
                    <td style={styleAllBorders}>{v.machine_name}</td>
                    <td style={styleAllBorders}>{v.line_name}</td>
                    <td style={{ width: '140px', ...styleAllBorders }}>{v.request_user_name}</td>
                    <td style={styleAllBorders}>{util.getDateText(v.request_time, true)}</td>
                    <td style={styleAllBorders}>{v.request_cause}</td>
                    <td style={styleAllBorders}>{v.repair_user_name}</td>
                    <td style={styleAllBorders}>{util.getDateText(v.repair_time, true)}</td>
                    <td style={styleAllBorders}>{util.getDateText(v.finish_time, true)}</td>
                    <td style={styleAllBorders}>{respondTime}</td>
                    <td style={styleAllBorders}>{repairTime}</td>
                    <td style={styleAllBorders}>{downTime}</td>
                    <td style={styleAllBorders}>{v.finish_work_type}</td>
                    {/* <td style={styleAllBorders}>{v.finish_cause}</td>
                    <td style={styleAllBorders}>{v.code}</td> */}
                </tr>
            )
        });

        // TROUBLE MACHINE has to be at least 4 as to comply with HLT format.
        if (troubleMachines.length < 4) {
            for (let i = troubleMachines.length; i < 4; i++) {
                troubleMachines.push(
                    <tr key={`trouble-machine-fulfill-key-${i}`}>
                        <td style={styleAllBorders}>&nbsp;</td>
                        <td style={styleAllBorders}>&nbsp;</td>
                        <td colSpan={2} style={styleAllBorders}>&nbsp;</td>
                        <td style={styleAllBorders}>&nbsp;</td>
                        <td colSpan={3} style={styleAllBorders}>&nbsp;</td>
                        <td style={styleAllBorders}>&nbsp;</td>
                        <td style={styleAllBorders}>&nbsp;</td>
                        <td style={styleAllBorders}>&nbsp;</td>
                    </tr>
                )
            }
        }


        totalRepairTime += totalSetupTime + totalBreakdownTime + totalOtherTime;
        let successRate = `${((totalRepairJobs - unfinishedJob) / totalRepairJobs * 100).toFixed(0)}%`
        totalRepairMan = repairManMap.size
        console.log('man', repairManMap)

        let d = moment.duration(Math.floor(totalRepairTime / totalRepairJobs));
        // averageRepairTime = util.getDurationTimeInMinuteText(Math.floor(totalRepairTime / totalRepairJobs))
        averageRepairTime = util.getDurationTimeInMinuteText(Math.floor(totalRunMachineTime / totalRepairMan))

        console.log(totalRepairTime, totalRepairJobs, Math.floor(totalRepairTime / totalRepairJobs))

        // averageRepairTime = moment(totalRepairTime/totalRepairJobs).format('HH:mm:ss')

        return (
            <Container fluid style={{ backgroundColor: '#ffffff', minHeight: '100vh', minWidth: '100vw' }}>
                <ReactHTMLTableToExcel
                    id="test-table-xls-button"
                    className="download-table-xls-button"
                    table="report"
                    filename="DailyReport"
                    sheet="daily1"
                    buttonText="Download as XLS" />
                {/* 
                <Table id="report" bordered hover size="xl">
                    <tbody>
                        <tr>
                            <td style={styleAllBorders}><b>Honda Lock</b></td>
                            <td style={styleAllBorders}><b>Honda Lock Thai Co.,Ltd.</b></td>
                            <td className="r">ฝ่ายควบคุม : MANUFACTURING  ENGINEERING</td>
                        </tr>
                    </tbody>
                </Table>
                <Row>
                    <Col>
                        <h3>LIST REPAIRING TABLE FOR MACHINE PRODUCTION FOR MARCH</h3>
                    </Col>
                    <Col md={4}>
                        <h3>DATE: {moment(this.props.startDate).format('DD MMM YYYY')} - {moment(this.props.endDate).format('DD MMM YYYY')}</h3>
                    </Col>
                </Row> */}


                <table id="report" >
                    <thead>
                        <tr>
                            <td style={styleNoBorders}><img src={logo} alt="logo"/></td>
                            <td colSpan={14} style={{...styleNoBorders, textAlign:'left'}}>
                                <h1>Honda Lock</h1>
                            </td>
                        </tr>
                        <tr>
                            <td colSpan={8}><b>Honda Lock Thai Co.,Ltd.</b></td>
                            <td colSpan={7} style={{ textAlign: 'right' }}><b>ฝ่ายควบคุม : MANUFACTURING  ENGINEERING</b></td>
                        </tr>
                        <tr style={{
                            borderTop: 'thin solid #000',
                            borderBottom: 'thin thin #000',
                        }}>
                            <td colSpan={8} style={{ textAlign: 'center' }}>
                                <h3>LIST REPAIRING TABLE FOR MACHINE PRODUCTION FOR MARCH</h3>
                            </td>
                            <td colSpan={6} className="c">
                                <h3>DATE: {moment(this.props.startDate).format('DD MMM YYYY')} - {moment(this.props.endDate).format('DD MMM YYYY')}</h3>
                            </td>
                            <td className="c">
                                <h3>S1+S2</h3>
                            </td>
                        </tr>
                        <tr style={{height: '24px'}}>
                            <th style={styleAllBorders}>No</th>
                            <th style={styleAllBorders}>Code</th>
                            <th style={styleAllBorders}>Machine Code</th>
                            <th style={{...styleAllBorders, width: '200px'}}>Machine Name</th>
                            <th style={styleAllBorders}>Line</th>
                            <th style={styleAllBorders}>Request Name</th>
                            <th style={styleAllBorders}>Request Time</th>
                            <th style={{...styleAllBorders, width: '200px'}}>Cause</th>
                            <th style={styleAllBorders}>Repair Name</th>
                            <th style={styleAllBorders}>Repair Time</th>
                            <th style={styleAllBorders}>Finish Time</th>
                            <th style={{...styleAllBorders, width: '120px'}}>Time Before Repair</th>
                            <th style={{...styleAllBorders, width: '120px'}}>Repair Time</th>
                            <th style={{...styleAllBorders, width: '120px'}}>Total Time Break Down</th>
                            <th style={styleAllBorders}>Breakdown / Setup</th>
                            {/* <th style={styleAllBorders}>Caused From</th>
                            <th style={styleAllBorders}>Change Profile Form No.</th> */}

                        </tr>
                    </thead>
                    <tbody>
                        {jobs}
                        <tr style={{ height: '40px' }}>
                            <td colSpan={3} style={styleAllBorders}>Total Repair List</td><td style={styleAllBorders}>{totalRepairJobs}</td>
                            <td colSpan={2} style={styleAllBorders}>Setup</td><td style={styleAllBorders}>{totalSetupJobs}</td>
                            <td style={styleAllBorders}>Breakdown</td><td style={styleAllBorders}>{totalBreakdownJobs}</td>
                            <td style={styleAllBorders}>Other</td><td style={styleAllBorders}>{totalOtherJobs}</td>
                            <td style={{ textAlign: 'center' }} colSpan={3} rowSpan={2}>อัตราผลสำเร็จ</td>
                            <td style={{ textAlign: 'center' }}>{successRate}</td>
                        </tr>
                        <tr style={{ height: '40px' }}>
                            <td colSpan={3} style={styleAllBorders}>Total Repair Time</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalRepairTime)}</td>
                            <td colSpan={2} style={styleAllBorders}>Setup Time</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalSetupTime)}</td>
                            <td style={styleAllBorders}>Breakdown Time</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalBreakdownTime)}</td>
                            <td style={styleAllBorders}>Other Time</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalOtherTime)}</td>
                            <td align="center"><div style={cssCirlcle}></div></td>
                        </tr>
                        <tr style={{ height: '40px' }}>
                            <td colSpan={3} style={styleAllBorders}>All Run Machine Times</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalRunMachineTime)}</td>
                            <td colSpan={2} style={styleAllBorders}>Total Repair</td><td style={styleAllBorders}>{totalRepairMan} men</td>
                            <td style={styleAllBorders}>Average for Repair Times</td><td style={styleAllBorders}>{averageRepairTime}</td>
                            <td style={styleAllBorders}>Wait For Repair</td><td style={styleAllBorders}>{util.getDurationTimeInMinuteText(totalWaitForRepairTime)}</td>
                            <td colSpan={4} style={styleAllBorders}>Wait For Repair  {totalWaitForRepairTime}   Minute</td>

                        </tr>

                        <tr>
                            <td colSpan={15}>
                                <h3 style={{ color: 'red' }}>** TROUBLER EVENT FOR REPAIR MACHINE</h3>
                            </td>
                        </tr>
                        <tr>
                            <th style={styleAllBorders}>No</th>
                            <th style={styleAllBorders}>Machine Code</th>
                            <th colSpan={2} style={styleAllBorders}>Machine Name</th>
                            <th style={styleAllBorders}>Line</th>
                            <th colSpan={3} style={styleAllBorders}>Cause</th>
                            <th style={styleAllBorders}>Repair Name</th>
                            <th style={styleAllBorders}>Repair Time</th>
                            <th style={styleAllBorders}>Result</th>
                            <td align="center" colSpan={4} rowSpan={troubleMachines.length+1}>
                                <table style={{ width: '90%'}}>
                                    <thead>
                                        <tr>
                                            <th style={styleAllBorders}>ISSUED</th>
                                            <th style={styleAllBorders}>CHECK</th>
                                            <th style={styleAllBorders}>APPROVED</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr style={{ height: '60px'}}>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                        </tr>
                                        <tr>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                            <td style={styleAllBorders}>&nbsp;</td>
                                        </tr>
                                    </tbody>
                                </table>
                            </td>
                        </tr>
                        {troubleMachines}

                    </tbody>
                </table>

            </Container >
        )
    }
}

